package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.ThrowStmt;
import com.github.javaparser.ast.expr.TypeExpr;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.stream.Stream;

public class Main {
    public static void main(String[] args) throws IOException {
        String sourceDir = "/workspace/license-maven-plugin/license-maven-plugin/src/main/java";

        Path sourcePath = Paths.get(sourceDir);
        try (Stream<Path> paths = Files.walk(sourcePath)) {
            paths.filter(Files::isRegularFile)
                 .filter(p -> p.toString().endsWith(".java"))
                 .forEach(Main::fixCompilationError);
        }
    }

    private static void fixCompilationError(Path filePath) {
        try {
            CompilationUnit cu = StaticJavaParser.parse(filePath);
            boolean modified = false;

            // Remove the problematic import
            cu.getImports().stream()
              .filter(importDecl -> importDecl.getNameAsString()
                  .equals("org.apache.maven.shared.dependency.graph.internal.Maven31DependencyGraphBuilder"))
              .findFirst()
              .ifPresent(importDecl -> {
                  importDecl.remove();
                  modified = true;
              });

            // Find and fix the setGraph method
            cu.findAll(MethodDeclaration.class).stream()
              .filter(method -> method.getNameAsString().equals("setGraph"))
              .forEach(method -> {
                  method.getBody().ifPresent(body -> {
                      body.getStatements().stream()
                          .filter(stmt -> stmt instanceof com.github.javaparser.ast.expr.ExpressionStmt)
                          .map(stmt -> (com.github.javaparser.ast.expr.ExpressionStmt) stmt)
                          .filter(exprStmt -> exprStmt.getExpression() instanceof com.github.javaparser.ast.expr.AssignExpr)
                          .map(exprStmt -> (com.github.javaparser.ast.expr.AssignExpr) exprStmt.getExpression())
                          .filter(assignExpr -> assignExpr.getTarget() instanceof NameExpr)
                          .filter(assignExpr -> ((NameExpr) assignExpr.getTarget()).getNameAsString().equals("this.graph"))
                          .filter(assignExpr -> assignExpr.getValue() instanceof com.github.javaparser.ast.expr.MethodCallExpr)
                          .map(assignExpr -> (com.github.javaparser.ast.expr.MethodCallExpr) assignExpr.getValue())
                          .filter(callExpr -> callExpr.getNameAsString().equals("orElse"))
                          .forEach(callExpr -> {
                              callExpr.getArguments().stream()findFirst()
                                  .filter(arg -> arg instanceof ObjectCreationExpr)
                                  .map(arg -> (ObjectCreationExpr) arg)
                                  .filter(creation -> creation.getType().asString()
                                      .equals("Maven31DependencyGraphBuilder"))
                                  .ifPresent(creation -> {
                                      ThrowStmt throwStmt = new ThrowStmt(
                                          new ObjectCreationExpr()
                                              .setType("IllegalStateException")
                                              .addArgument("\"DependencyGraphBuilder cannot be null\"")
                                      );
                                      callExpr.replace(throwStmt);
                                      modified = true;
                                  });
                          });
                  });
              });

            if (modified) {
                Files.writeString(filePath, cu.toString());
                System.out.println("Fixed: " + filePath);
            }
        } catch (Exception e) {
            System.err.println("Error processing " + filePath + ": " + e.getMessage());
        }
    }
}

